class Solution:
    def generateString(self, str1, str2):
        n, m = len(str1), len(str2)
        L = n + m - 1
        forced = [None] * L
        for i in range(n):
            if str1[i] == 'T':
                for j in range(m):
                    pos = i + j
                    c = str2[j]
                    if forced[pos] is not None and forced[pos] != c:
                        return ""
                    forced[pos] = c
        used = sorted(set(str2)) or ['a']
        extra = chr(ord(max(used)) + 1)
        candidates = sorted(set(used) | {'a', extra})
        word = [None] * L
        target = str2

        def windows_ok(pos):
            lo = max(0, pos - m + 1)
            hi = min(pos, n - 1)
            for i in range(lo, hi + 1):
                if str1[i] != 'F':
                    continue
                end = i + m - 1
                if end != pos:
                    continue
                if all(word[i + j] == target[j] for j in range(m)):
                    return False
            return True

        def backtrack(pos):
            if pos == L:
                return True
            if forced[pos] is not None:
                word[pos] = forced[pos]
                if windows_ok(pos) and backtrack(pos + 1):
                    return True
                word[pos] = None
                return False
            for c in candidates:
                word[pos] = c
                if windows_ok(pos) and backtrack(pos + 1):
                    return True
            word[pos] = None
            return False

        return ''.join(word) if backtrack(0) else ""

