class Solution:
    def generateString(self, str1, str2):
        n, m = len(str1), len(str2)
        L = n + m - 1
        word = ['a'] * L
        fixed = [False] * L
        for i in range(n):
            if str1[i] == 'T':
                for j in range(m):
                    pos = i + j
                    c = str2[j]
                    if fixed[pos] and word[pos] != c:
                        return ""
                    word[pos] = c
                    fixed[pos] = True
        target = list(str2)
        changed = True
        while changed:
            changed = False
            for i in range(n):
                if str1[i] != 'F':
                    continue
                if word[i:i + m] == target:
                    fix_pos = -1
                    for pos in range(i + m - 1, i - 1, -1):
                        if not fixed[pos]:
                            fix_pos = pos
                            break
                    if fix_pos == -1:
                        return ""
                    nxt = chr(ord(word[fix_pos]) + 1)
                    if nxt > 'z':
                        return ""
                    word[fix_pos] = nxt
                    changed = True
        return ''.join(word)

