var generateString = function(str1, str2) {
    const n = str1.length, m = str2.length;
    const L = n + m - 1;
    const word = new Array(L).fill('a');
    const fixed = new Array(L).fill(false);
    for (let i = 0; i < n; i++) {
        if (str1[i] === 'T') {
            for (let j = 0; j < m; j++) {
                const pos = i + j;
                const c = str2[j];
                if (fixed[pos] && word[pos] !== c) return "";
                word[pos] = c;
                fixed[pos] = true;
            }
        }
    }
    let changed = true;
    while (changed) {
        changed = false;
        for (let i = 0; i < n; i++) {
            if (str1[i] !== 'F') continue;
            let matches = true;
            for (let j = 0; j < m; j++) {
                if (word[i + j] !== str2[j]) { matches = false; break; }
            }
            if (!matches) continue;
            let fixPos = -1;
            for (let pos = i + m - 1; pos >= i; pos--) {
                if (!fixed[pos]) { fixPos = pos; break; }
            }
            if (fixPos === -1) return "";
            const nxt = String.fromCharCode(word[fixPos].charCodeAt(0) + 1);
            if (nxt > 'z') return "";
            word[fixPos] = nxt;
            changed = true;
        }
    }
    return word.join('');
};
